# Запуск только тестов QueryIntersectApiTest с двумя куками
# Использование: отредактируйте значения ниже и выполните .\run-query-tests-two-cookies.ps1

# Первая кука (основная) — вставьте своё значение между кавычками
$env:cookie = " "
# Вторая кука (cookie_autotest) — вставьте своё значение между кавычками
$env:cookie_autotest = "
request_uri=Lw==; OAuth_Token_Request_State=afc98985-81d7-4803-bc31-9bdf34672060; kc-; kc-"

# Передаём куки в Maven явно как -D, чтобы форк Surefire их получил (Config.getCookie() читает system property).
# Если появится ошибка "command line too long" — замените строку ниже на: mvn test -Dtest=QueryIntersectApiTest
# (тогда куки возьмутся из $env:cookie и $env:cookie_autotest в форке).
if (-not $env:cookie) {
    Write-Warning "Переменная cookie не задана. Заполните `$env:cookie в начале скрипта."
}
Write-Host "Запуск тестов QueryIntersectApiTest с двумя куками (cookie и cookie_autotest)..."
mvn test -Dtest=QueryIntersectApiTest -Dcookie="$env:cookie" -Dcookie_autotest="$env:cookie_autotest"


